proof fn phi_1_always_unfold_extensional_gap(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_2_always_and_reverse_not_proven(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        always(p).satisfied_by(ex),
        always(q).satisfied_by(ex),
    ensures
        always(p.and(q)).satisfied_by(ex),
{
    always_unfold::<int>(ex, p);
    always_unfold::<int>(ex, q);
}

